package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testNewFormat() {
        char delimiter = ';';
        CSVFormat format = CSVFormat.newFormat(delimiter);

        assertNotNull(format);
        assertEquals(delimiter, format.getDelimiter());
        assertEquals(null, format.getQuoteCharacter());
        assertEquals(null, format.getQuoteMode());
        assertEquals(null, format.getCommentMarker());
        assertEquals(null, format.getEscapeCharacter());
        assertFalse(format.getIgnoreSurroundingSpaces());
        assertFalse(format.getIgnoreEmptyLines());
        assertEquals(null, format.getRecordSeparator());
        assertEquals(null, format.getNullString());
        assertEquals(null, format.getHeader());
        assertFalse(format.getSkipHeaderRecord());
        assertFalse(format.getAllowMissingColumnNames());
    }
}
